mapper.select:
SELECT 
FROM merchant_shop_change c JOIN merchant m ON m.id=c.merchant_id
WHERE c.id=#{changeId} AND c.merchant_id=#{merchantId} AND c.region=#{region}

mapper.sql:
WHERE c.merchant_id=#{merchantId} AND c.region=#{region}
AND c.target_shop_id=#{shopId}

    AND c.target_shop_id=0


    AND (c.target_shop_id=0 OR c.target_shop_id IN
    #{id})

AND c.status=#{status}
AND c.change_type=#{changeType}

mapper.select:
SELECT 
FROM merchant_shop_change c JOIN merchant m ON m.id=c.merchant_id

ORDER BY c.id DESC LIMIT #{limit} OFFSET #{offset}
